import React, { useState, useEffect, useRef } from 'react';
import { Moon, Sun, Mail, Phone, MapPin, Github, Linkedin, ExternalLink, Code, Briefcase, GraduationCap, Award } from 'lucide-react';

// Custom Scroll Reveal Component for elegant fade-in animations
const RevealOnScroll = ({ children, className = "", delay = 0, animation = "fade-up" }) => {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setIsVisible(true);
        observer.unobserve(entry.target);
      }
    }, { threshold: 0.1, rootMargin: "0px 0px -50px 0px" });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  const getClasses = () => {
    if (isVisible) {
      switch(animation) {
        case "fade-left":
        case "fade-right": return "opacity-100 translate-x-0";
        case "zoom-in": return "opacity-100 scale-100";
        default: return "opacity-100 translate-y-0 scale-100";
      }
    } else {
      switch(animation) {
        case "fade-left": return "opacity-0 -translate-x-20";
        case "fade-right": return "opacity-0 translate-x-20";
        case "zoom-in": return "opacity-0 scale-75";
        default: return "opacity-0 translate-y-16 scale-95";
      }
    }
  };

  return (
    <div ref={ref} style={{ transitionDelay: `${delay}ms` }} className={`transition-all duration-1000 ease-out transform ${getClasses()} ${className}`}>
      {children}
    </div>
  );
};

function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [typedText, setTypedText] = useState('');
  const fullText = "Sneha Madavali";

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    // Enable smooth scrolling for the entire page
    document.documentElement.style.scrollBehavior = 'smooth';
  }, [darkMode]);

  // Typing effect animation
  useEffect(() => {
    let index = 0;
    const timer = setInterval(() => {
      if (index <= fullText.length) {
        setTypedText(fullText.slice(0, index));
        index++;
      } else {
        clearInterval(timer);
      }
    }, 150); // Adjust typing speed here (milliseconds)
    return () => clearInterval(timer);
  }, []);

  const skills = [
    { category: 'Languages', items: ['Java', 'Python', 'JavaScript'] },
    { category: 'Mobile Development', items: ['React Native', 'Expo'] },
    { category: 'Web & Database', items: ['HTML5', 'CSS3', 'SQL'] },
    { category: 'Core Concepts', items: ['OOP', 'Data Structures', 'CRUD Operations', 'REST API', 'Deep Learning (CNNs)'] },
    { category: 'Tools', items: ['Git', 'GitHub', 'VS Code'] }
  ];

  const projects = [
    {
      title: 'Smart Task Mobile Application',
      description: 'Developed a full-featured task management app with CRUD functionality using AsyncStorage and React Hooks. Designed a user-friendly interface to enhance productivity and task organization.',
      technologies: ['React Native', 'AsyncStorage', 'React Hooks'],
      github: 'https://github.com/snehasneha1050-spec/Smart-Tasks-App'
    },
    {
      title: 'Real-Time Visual Object Recognition',
      description: 'Engineered a deep learning framework using CNNs for high-accuracy object detection in live video feeds. Implemented automated feature extraction to balance processing speed and detection precision for IoT applications.',
      technologies: ['Python', 'Deep Learning', 'CNNs', 'Computer Vision'],
      github: 'https://github.com/snehasneha1050-spec'
    },
    {
      title: 'Weather App',
      description: 'A weather application providing real-time weather information and forecasts.',
      technologies: ['JavaScript', 'API Integration'],
      github: 'https://github.com/snehasneha1050-spec/Weather-App'
    }
  ];

  const experience = [
    {
      company: 'Tekinspy Software Services',
      position: 'Software Developer Intern',
      duration: 'January - Ongoing',
      description: [
        'Leading the development of the "Smart Task" mobile application using React Native',
        'Integrating local storage for task persistence and optimizing application performance'
      ]
    },
    {
      company: 'InternsVeda',
      position: 'Web Development Intern',
      duration: 'May 2020 - June 2025',
      description: [
        'Developed responsive web pages using HTML5 and CSS3',
        'Ensuring accessibility and mobile responsiveness'
      ]
    },
    {
      company: 'TeknoSpire',
      position: 'Core Java Intern',
      duration: '1st June 2025 - 30th June 2025',
      description: [
        'Developed modular Java programs utilizing core OOP principles',
        'Implemented standard data structures'
      ]
    }
  ];

  const education = [
    {
      degree: 'B.Tech - Computer Science Engineering',
      institution: 'Chadalawada Ramanamma Engineering College, Tirupati',
      grade: '86%'
    },
    {
      degree: 'Intermediate (MPC)',
      institution: 'School',
      grade: '80%'
    },
    {
      degree: 'SSC (10th Standard)',
      institution: 'School',
      grade: '100%'
    }
  ];

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-gray-100 font-sans selection:bg-blue-200 selection:text-blue-900 dark:selection:bg-blue-800 dark:selection:text-blue-100 relative overflow-hidden">
      
      {/* Inject Custom CSS for Advanced Animations */}
      <style dangerouslySetInnerHTML={{__html: `
        @keyframes float {
          0% { transform: translateY(0px); }
          50% { transform: translateY(-20px); }
          100% { transform: translateY(0px); }
        }
        @keyframes blob {
          0% { transform: translate(0px, 0px) scale(1); }
          33% { transform: translate(30px, -50px) scale(1.1); }
          66% { transform: translate(-20px, 20px) scale(0.9); }
          100% { transform: translate(0px, 0px) scale(1); }
        }
        @keyframes shine {
          0% { left: -100%; }
          100% { left: 200%; }
        }
        @keyframes gradient-x {
          0%, 100% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
        }
        @keyframes wiggle {
          0%, 100% { transform: rotate(-10deg); }
          50% { transform: rotate(10deg); }
        }
        .animate-float { animation: float 6s ease-in-out infinite; }
        .animate-blob { animation: blob 8s infinite alternate; }
        .animate-gradient-x { animation: gradient-x 3s ease infinite; background-size: 200% 200%; }
        .animate-wiggle { animation: wiggle 2s ease-in-out infinite; }
        .animation-delay-2000 { animation-delay: 2s; }
        .animation-delay-4000 { animation-delay: 4s; }
        .glass-panel { background: rgba(255, 255, 255, 0.6); backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px); }
        .dark .glass-panel { background: rgba(31, 41, 55, 0.6); }
        .hover-shine::after {
          content: ''; position: absolute; top: 0; left: -100%; width: 50%; height: 100%;
          background: linear-gradient(to right, transparent, rgba(255,255,255,0.25), transparent);
          transform: skewX(-20deg); pointer-events: none; z-index: 20;
        }
        .hover-shine:hover::after { animation: shine 1.5s ease-out infinite; }
      `}} />

      {/* Decorative Background Blobs */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[-10%] left-[-10%] w-[40rem] h-[40rem] bg-blue-400/30 dark:bg-blue-600/20 rounded-full blur-3xl animate-blob"></div>
        <div className="absolute top-[20%] right-[-10%] w-[35rem] h-[35rem] bg-purple-400/30 dark:bg-purple-600/20 rounded-full blur-3xl animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-10%] left-[20%] w-[45rem] h-[45rem] bg-indigo-400/30 dark:bg-indigo-600/20 rounded-full blur-3xl animate-blob animation-delay-4000"></div>
        <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 brightness-100 contrast-150 mix-blend-overlay"></div>
      </div>

      {/* Navigation */}
      <nav className="fixed top-0 w-full glass-panel z-50 border-b border-gray-200/50 dark:border-gray-800/50 shadow-sm transition-colors duration-300">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between items-center">
          <h1 className="text-2xl font-black bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 tracking-wide cursor-pointer hover:opacity-80 transition-opacity">Sneha.</h1>
          <div className="flex items-center space-x-4 md:space-x-8 text-sm md:text-base font-medium">
            <a href="#about" className="hidden md:block hover:text-blue-600 dark:hover:text-blue-400 transition-colors">About</a>
            <a href="#skills" className="hidden md:block hover:text-blue-600 dark:hover:text-blue-400 transition-colors">Skills</a>
            <a href="#projects" className="hover:text-blue-600 dark:hover:text-blue-400 transition-colors">Projects</a>
            <a href="#experience" className="hover:text-blue-600 dark:hover:text-blue-400 transition-colors">Experience</a>
            <a href="#contact" className="hidden md:block hover:text-blue-600 dark:hover:text-blue-400 transition-colors">Contact</a>
            <button
              onClick={() => setDarkMode(!darkMode)}
              className="p-2 rounded-full hover:bg-gray-200 dark:hover:bg-gray-800 text-gray-600 dark:text-gray-300 transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
              aria-label="Toggle Dark Mode"
            >
              {darkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="pt-32 pb-20 px-4">
        <div className="max-w-6xl mx-auto text-center">
          <RevealOnScroll animation="zoom-in">
            <div className="relative w-48 h-48 mx-auto mb-10 group animate-float">
              <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-purple-600 rounded-full animate-pulse blur-2xl opacity-60 group-hover:opacity-100 transition-opacity duration-700"></div>
              <img 
                src="/profile.jpg" 
                alt="Sneha Madavali" 
                className="relative w-full h-full object-cover rounded-full border-4 border-white dark:border-gray-800 shadow-2xl transform group-hover:scale-105 group-hover:rotate-3 transition-all duration-500 bg-white dark:bg-gray-800"
                onError={(e) => { e.target.onerror = null; e.target.src = "https://ui-avatars.com/api/?name=Sneha+Madavali&background=3b82f6&color=fff&size=200&bold=true"; }}
              />
            </div>
          </RevealOnScroll>
          <RevealOnScroll animation="fade-up" delay={100}>
            <h1 className="text-5xl md:text-7xl font-extrabold mb-6 tracking-tight min-h-[4rem] md:min-h-[5.5rem]">
              Hi, I'm <span className="bg-clip-text text-transparent bg-gradient-to-r from-blue-600 via-indigo-500 to-purple-600 animate-gradient-x">{typedText}</span>
              <span className="text-purple-600 animate-pulse ml-1">|</span>
            </h1>
            <p className="text-xl md:text-2xl text-gray-600 dark:text-gray-400 mb-10 max-w-3xl mx-auto leading-relaxed">
              Recent Computer Science Engineering Graduate with hands-on experience in mobile application development using React Native and Expo. Skilled in Java, Python, and SQL, with a focus on building scalable applications and implementing Deep Learning models for real-world computer vision solutions.
            </p>
          </RevealOnScroll>
          <RevealOnScroll delay={300} animation="fade-up" className="flex justify-center space-x-4">
            <a href="https://github.com/snehasneha1050-spec" target="_blank" rel="noreferrer" className="group inline-flex items-center px-7 py-3.5 bg-gray-900 dark:bg-white text-white dark:text-gray-900 font-semibold rounded-2xl transition-all duration-300 shadow-xl hover:shadow-2xl hover:shadow-gray-900/20 dark:hover:shadow-white/20 transform hover:-translate-y-2 hover:scale-105">
              <Github className="inline mr-2 group-hover:animate-wiggle" size={20} />
              GitHub
            </a>
            <a href="https://www.linkedin.com/in/madavali-sneha-97563726a" target="_blank" rel="noreferrer" className="group inline-flex items-center px-7 py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white font-semibold rounded-2xl transition-all duration-300 shadow-xl hover:shadow-2xl hover:shadow-blue-500/30 transform hover:-translate-y-2 hover:scale-105">
              <Linkedin className="inline mr-2 group-hover:animate-wiggle" size={20} />
              LinkedIn
            </a>
          </RevealOnScroll>
        </div>
      </section>

      {/* About Section */}
      <section id="about" className="py-20 px-4 max-w-6xl mx-auto">
        <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">About Me</h2></RevealOnScroll>
        <div className="grid md:grid-cols-2 gap-12 items-center">
          <RevealOnScroll delay={100} animation="fade-right">
            <p className="text-lg mb-6 leading-relaxed">
              I'm a passionate software developer with a strong foundation in computer science and engineering. My journey in technology has been driven by curiosity and the desire to create solutions that make a difference.
            </p>
            <p className="text-lg mb-6 leading-relaxed">
              Through my internships and projects, I've gained valuable experience in mobile app development, web technologies, and deep learning. I'm always eager to learn new technologies and tackle challenging problems.
            </p>
            <div className="flex items-center space-x-4 text-gray-600 dark:text-gray-400 font-medium">
              <MapPin size={22} className="text-blue-600 dark:text-blue-400" />
              <span>Punganur, Andhra Pradesh</span>
            </div>
          </RevealOnScroll>
          <RevealOnScroll delay={300} animation="fade-left" className="space-y-6 glass-panel p-8 rounded-3xl shadow-xl border border-white/20 dark:border-gray-700/50 transform hover:-translate-y-2 transition-all duration-500 hover:shadow-blue-500/10">
            <div className="flex items-center space-x-4">
              <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-2xl">
                <Code className="text-blue-600 dark:text-blue-400" size={24} />
              </div>
              <span className="text-lg font-medium">Full-Stack Developer</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-2xl">
                <Briefcase className="text-blue-600 dark:text-blue-400" size={24} />
              </div>
              <span className="text-lg font-medium">3+ Internships Completed</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-2xl">
                <GraduationCap className="text-blue-600 dark:text-blue-400" size={24} />
              </div>
              <span className="text-lg font-medium">B.Tech CSE Graduate</span>
            </div>
            <div className="flex items-center space-x-4">
              <div className="p-3 bg-blue-50 dark:bg-blue-900/30 rounded-2xl">
                <Award className="text-blue-600 dark:text-blue-400" size={24} />
              </div>
              <span className="text-lg font-medium">Problem Solver & Team Player</span>
            </div>
          </RevealOnScroll>
        </div>
      </section>

      {/* Skills Section */}
      <section id="skills" className="py-24 glass-panel border-y border-gray-200/50 dark:border-gray-800/50">
        <div className="max-w-6xl mx-auto px-4">
          <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">Technical Skills</h2></RevealOnScroll>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {skills.map((skillGroup, index) => (
              <RevealOnScroll key={index} delay={index * 100} animation="zoom-in">
                <div className="bg-white dark:bg-gray-800/80 rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all duration-500 border border-gray-100 dark:border-gray-700 hover:-translate-y-2 group relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-blue-500 to-purple-600 transform origin-left scale-x-0 group-hover:scale-x-100 transition-transform duration-500 ease-out"></div>
                  <h3 className="text-2xl font-bold mb-6 text-gray-900 dark:text-white group-hover:text-blue-500 transition-colors">{skillGroup.category}</h3>
                  <div className="flex flex-wrap gap-3">
                    {skillGroup.items.map((skill, skillIndex) => (
                      <span key={skillIndex} style={{ transitionDelay: `${skillIndex * 50}ms` }} className="px-4 py-2 bg-gray-50 dark:bg-gray-900/50 text-gray-700 dark:text-gray-300 rounded-xl text-sm font-semibold shadow-sm border border-gray-200 dark:border-gray-700 hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 hover:scale-105 hover:-translate-y-1 hover:animate-wiggle transition-all duration-300 cursor-default">
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
              </RevealOnScroll>
            ))}
          </div>
        </div>
      </section>

      {/* Projects Section */}
      <section id="projects" className="py-24 px-4 max-w-6xl mx-auto">
        <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">Featured Projects</h2></RevealOnScroll>
        <div className="grid md:grid-cols-2 gap-8">
          {projects.map((project, index) => (
            <RevealOnScroll key={index} delay={index * 150} animation="fade-up" className="relative group h-full">
              <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-600 to-purple-600 rounded-[2rem] blur opacity-25 group-hover:opacity-75 transition duration-1000 group-hover:duration-200"></div>
              <div className="relative h-full bg-white/90 dark:bg-gray-900/90 backdrop-blur-xl rounded-3xl p-8 shadow-xl border border-white/20 dark:border-gray-700/50 flex flex-col overflow-hidden hover-shine">
                <div className="absolute top-[-50px] right-[-50px] w-32 h-32 bg-blue-500/10 rounded-full blur-2xl group-hover:scale-150 transition-transform duration-700"></div>
                <h3 className="text-2xl font-bold mb-4 text-gray-900 dark:text-white group-hover:text-blue-500 transition-colors">{project.title}</h3>
                <p className="text-gray-600 dark:text-gray-400 mb-6 flex-grow leading-relaxed text-lg">{project.description}</p>
                <div className="flex flex-wrap gap-2 mb-8">
                  {project.technologies.map((tech, techIndex) => (
                    <span key={techIndex} className="px-4 py-1.5 bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 rounded-xl text-sm font-bold border border-blue-100 dark:border-blue-800/50">
                      {tech}
                    </span>
                  ))}
                </div>
                <div className="mt-auto pt-6 border-t border-gray-100 dark:border-gray-800">
                  <a href={project.github} target="_blank" rel="noreferrer" className="inline-flex items-center text-gray-900 dark:text-white hover:text-blue-600 dark:hover:text-blue-400 font-bold transition-all transform group-hover:translate-x-2">
                    <Github size={22} className="mr-2" />
                    View on GitHub
                    <ExternalLink size={18} className="ml-1.5 opacity-0 -translate-x-2 group-hover:opacity-100 group-hover:translate-x-0 transition-all duration-300" />
                  </a>
                </div>
              </div>
            </RevealOnScroll>
          ))}
        </div>
      </section>

      {/* Experience Section */}
      <section id="experience" className="py-24 glass-panel border-y border-gray-200/50 dark:border-gray-800/50 relative">
        <div className="max-w-4xl mx-auto px-4">
          <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">Professional Experience</h2></RevealOnScroll>
          <div className="space-y-8">
            {experience.map((exp, index) => (
              <RevealOnScroll key={index} delay={index * 150} animation="fade-left">
                <div className="bg-white dark:bg-gray-800/90 rounded-3xl p-8 shadow-lg hover:shadow-2xl transition-all duration-500 border border-gray-100 dark:border-gray-700 relative overflow-hidden group hover:-translate-y-2">
                  <div className="absolute top-0 left-0 w-2 h-full bg-gradient-to-b from-blue-500 to-purple-600 transform origin-top scale-y-0 group-hover:scale-y-100 transition-transform duration-500"></div>
                  
                  <div className="flex flex-col md:flex-row md:justify-between md:items-start mb-6 relative z-10 pl-4">
                    <div>
                      <h3 className="text-2xl font-bold mb-2 text-gray-900 dark:text-white group-hover:text-blue-500 transition-colors">{exp.position}</h3>
                      <p className="text-blue-600 dark:text-blue-400 font-bold text-lg flex items-center">
                        <Briefcase size={18} className="mr-2" />
                        {exp.company}
                      </p>
                    </div>
                    <span className="inline-block mt-4 md:mt-0 px-5 py-2 bg-gray-50 dark:bg-gray-900 text-blue-600 dark:text-blue-400 rounded-2xl text-sm font-bold shadow-sm border border-gray-100 dark:border-gray-800">{exp.duration}</span>
                  </div>
                  <ul className="space-y-4 pl-4">
                    {exp.description.map((item, itemIndex) => (
                      <li key={itemIndex} className="flex items-start text-gray-700 dark:text-gray-300 leading-relaxed text-lg">
                        <div className="w-2 h-2 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 mr-4 mt-2.5 flex-shrink-0 group-hover:scale-150 transition-transform"></div>
                        <span>{item}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </RevealOnScroll>
            ))}
          </div>
        </div>
      </section>

      {/* Education Section */}
      <section id="education" className="py-24 px-4 max-w-6xl mx-auto">
        <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">Education</h2></RevealOnScroll>
        <div className="grid md:grid-cols-3 gap-6 max-w-5xl mx-auto">
          {education.map((edu, index) => (
            <RevealOnScroll key={index} delay={index * 200} animation="zoom-in">
              <div className="glass-panel rounded-3xl p-8 shadow-xl hover:shadow-2xl transition-all duration-500 border border-white/40 dark:border-gray-700/50 text-center hover:-translate-y-3 group flex flex-col justify-between h-full relative overflow-hidden">
                <div className="absolute top-[-30px] left-[50%] -translate-x-1/2 w-20 h-20 bg-blue-500/20 rounded-full blur-xl group-hover:scale-150 transition-transform duration-500"></div>
                <div className="mb-6">
                  <div className="w-14 h-14 mx-auto bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center text-white mb-6 shadow-lg group-hover:rotate-12 transition-transform duration-300">
                    <GraduationCap size={28} />
                  </div>
                  <h3 className="text-xl font-bold mb-3 text-gray-900 dark:text-white">{edu.degree}</h3>
                  <p className="text-gray-600 dark:text-gray-400 text-md font-medium">{edu.institution}</p>
                </div>
                <div className="mt-auto pt-4">
                  <span className="inline-block px-6 py-2 bg-gray-900 dark:bg-white text-white dark:text-gray-900 font-bold rounded-xl shadow-md group-hover:scale-105 transition-transform">{edu.grade}</span>
                </div>
              </div>
            </RevealOnScroll>
          ))}
        </div>
      </section>

      {/* Contact Section */}
      <section id="contact" className="py-24 bg-gradient-to-b from-transparent to-blue-50/50 dark:to-blue-900/10">
        <div className="max-w-4xl mx-auto px-4">
          <RevealOnScroll><h2 className="text-4xl md:text-5xl font-extrabold text-center mb-16 bg-clip-text text-transparent bg-gradient-to-r from-blue-600 to-purple-600 animate-gradient-x">Get In Touch</h2></RevealOnScroll>
          <RevealOnScroll delay={200} animation="fade-up">
            <div className="bg-white/80 dark:bg-gray-800/80 backdrop-blur-xl rounded-[3rem] p-10 md:p-16 shadow-[0_20px_50px_rgba(8,_112,_184,_0.07)] dark:shadow-[0_20px_50px_rgba(0,_0,_0,_0.5)] border border-white/40 dark:border-gray-700/50 max-w-2xl mx-auto text-center transform hover:-translate-y-3 transition-transform duration-700 relative overflow-hidden group">
              <div className="absolute top-[-20%] right-[-10%] w-64 h-64 bg-gradient-to-br from-blue-500/20 to-purple-500/20 rounded-full blur-3xl pointer-events-none group-hover:scale-150 transition-transform duration-700"></div>
              <div className="absolute bottom-[-20%] left-[-10%] w-64 h-64 bg-gradient-to-tr from-indigo-500/20 to-blue-500/20 rounded-full blur-3xl pointer-events-none group-hover:scale-150 transition-transform duration-700"></div>
              
              <p className="text-2xl mb-12 text-gray-700 dark:text-gray-300 leading-relaxed font-medium relative z-10">
                I'm always open to discussing new opportunities, interesting projects, or just having a chat about technology!
              </p>
              <div className="space-y-8 relative z-10">
                <div className="flex items-center justify-center space-x-5 group/item cursor-pointer">
                  <div className="p-4 bg-blue-50 dark:bg-gray-900 rounded-2xl group-hover/item:scale-110 transition-transform shadow-sm">
                    <Mail className="text-blue-600 dark:text-blue-400" size={28} />
                  </div>
                  <a href="mailto:snehasneha1050@gmail.com" className="text-xl md:text-2xl font-bold hover:text-blue-600 dark:hover:text-blue-400 transition-colors">
                    snehasneha1050@gmail.com
                  </a>
                </div>
                <div className="flex items-center justify-center space-x-5 group/item">
                  <div className="p-4 bg-blue-50 dark:bg-gray-900 rounded-2xl group-hover/item:scale-110 transition-transform shadow-sm">
                    <Phone className="text-blue-600 dark:text-blue-400" size={28} />
                  </div>
                  <span className="text-xl md:text-2xl font-bold text-gray-800 dark:text-gray-200">+91-9014045023</span>
                </div>
                <div className="flex items-center justify-center space-x-5 group/item">
                  <div className="p-4 bg-blue-50 dark:bg-gray-900 rounded-2xl group-hover/item:scale-110 transition-transform shadow-sm">
                    <MapPin className="text-blue-600 dark:text-blue-400" size={28} />
                  </div>
                  <span className="text-xl md:text-2xl font-bold text-gray-800 dark:text-gray-200">Punganur, Andhra Pradesh</span>
                </div>
              </div>
              <div className="flex justify-center space-x-6 mt-16 relative z-10">
                <a href="https://github.com/snehasneha1050-spec" target="_blank" rel="noreferrer" className="group p-5 bg-gray-900 dark:bg-white rounded-2xl shadow-xl hover:shadow-2xl hover:-translate-y-2 text-white dark:text-gray-900 transition-all duration-300">
                  <Github size={30} className="group-hover:animate-wiggle" />
                </a>
                <a href="https://www.linkedin.com/in/madavali-sneha-97563726a" target="_blank" rel="noreferrer" className="group p-5 bg-blue-600 dark:bg-blue-500 rounded-2xl shadow-xl hover:shadow-2xl hover:shadow-blue-500/30 hover:-translate-y-2 text-white transition-all duration-300">
                  <Linkedin size={30} className="group-hover:animate-wiggle" />
                </a>
              </div>
            </div>
          </RevealOnScroll>
        </div>
      </section>

      {/* Footer */}
      <footer className="py-10 px-4 glass-panel text-center border-t border-gray-200/50 dark:border-gray-800/50 relative z-10">
        <p className="text-gray-600 dark:text-gray-400 font-medium">
          © 2026 Sneha Madavali. Built with React & Tailwind CSS.
        </p>
      </footer>
    </div>
  );
}

export default App;
